def solve(cities):
    t0 = time.time()
    n = len(cities)
    budget = 0.04 * n

    def dist(i, j):
        dx = cities[i][0] - cities[j][0]
        dy = cities[i][1] - cities[j][1]
        return int(math.sqrt(dx*dx + dy*dy) + 0.5)

    # Precompute candidate lists (k nearest neighbors)
    K = min(15, n - 1)
    candidates = []
    for i in range(n):
        dists = [(dist(i, j), j) for j in range(n) if j != i]
        dists.sort()
        candidates.append([j for _, j in dists[:K]])

    def tour_length(tour):
        return sum(dist(tour[i], tour[(i+1) % n]) for i in range(n))

    def nn_tour(start):
        visited = [False] * n
        tour = [start]
        visited[start] = True
        for _ in range(n - 1):
            cur = tour[-1]
            best_d = float('inf')
            best_j = -1
            for j in candidates[cur]:
                if not visited[j]:
                    d = dist(cur, j)
                    if d < best_d:
                        best_d = d
                        best_j = j
            if best_j == -1:
                for j in range(n):
                    if not visited[j]:
                        d = dist(cur, j)
                        if d < best_d:
                            best_d = d
                            best_j = j
            tour.append(best_j)
            visited[best_j] = True
        return tour

    def two_opt(tour):
        pos = [0] * n
        for i, c in enumerate(tour):
            pos[c] = i
        improved = True
        while improved:
            improved = False
            for idx in range(n):
                if time.time() - t0 >= budget * 0.95:
                    return tour
                i = tour[idx]
                i_next = tour[(idx + 1) % n]
                d_i = dist(i, i_next)
                for j in candidates[i]:
                    j_idx = pos[j]
                    if j_idx == idx or j_idx == (idx + 1) % n:
                        continue
                    j_next = tour[(j_idx + 1) % n]
                    if dist(i, j) >= d_i:
                        break
                    gain = d_i + dist(i_next, j_next) - dist(i, j) - dist(i_next, j_next)
                    # Recompute properly
                    gain = d_i + dist(i_next, j_next) - dist(i, j) - dist(j_next, i_next)
                    gain = dist(i, i_next) + dist(j, j_next) - dist(i, j) - dist(i_next, j_next)
                    if gain > 0:
                        # Reverse segment between idx+1 and j_idx
                        a, b = (idx + 1) % n, j_idx
                        if a <= b:
                            tour[a:b+1] = tour[a:b+1][::-1]
                        else:
                            # wrap-around
                            seg = tour[a:] + tour[:b+1]
                            seg.reverse()
                            tour[a:] = seg[:n-a]
                            tour[:b+1] = seg[n-a:]
                        for k2, c in enumerate(tour):
                            pos[c] = k2
                        improved = True
                        break
        return tour

    def or_opt(tour):
        # Or-opt: relocate single cities and pairs
        pos = [0] * n
        for i, c in enumerate(tour):
            pos[c] = i
        improved = True
        while improved:
